def process_data(items):
    """Process a list of items and return filtered results."""
    if not items:
        return  # BUG: should return []
    result = []
    for item in items:
        if isinstance(item, dict) and 'value' in item:
            if item['value'] > 0:
                result.append(item)
    return result

def aggregate(data_sources):
    all_items = []
    for source in data_sources:
        processed = process_data(source)
        all_items.extend(processed)  # crashes when process_data returns None
    return all_items

